function useIsMobile() {
  const [mobile, setMobile] = useState(typeof window !== "undefined" ? window.innerWidth < 900 : false);
  useEffect(() => {
    const h = () => setMobile(window.innerWidth < 900);
    window.addEventListener("resize", h);
    return () => window.removeEventListener("resize", h);
  }, []);
  return mobile;
}


function useInView(th = 0.07) {
  const r = useRef(null);
  const [v, setV] = useState(false);
  useEffect(() => {
    const el = r.current; if (!el) return;
    const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setV(true); o.disconnect(); } }, { threshold: th });
    o.observe(el); return () => o.disconnect();
  }, []);
  return [r, v];
}
function Fade({ children, d = 0, style = {} }) {
  const [r, v] = useInView();
  return (
    <div ref={r} style={{ ...style, opacity: v ? 1 : 0, transform: v ? "translateY(0)" : "translateY(22px)", transition: `opacity 0.85s cubic-bezier(.22,1,.36,1) ${d}s, transform 0.85s cubic-bezier(.22,1,.36,1) ${d}s` }}>
      {children}
    </div>
  );
}


// ── ANIMATED COUNTER (stats bar) ──
function useCountUp(target, inView, duration = 1800) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!inView) return;
    let start = null;
    const num = parseInt(target.replace(/\D/g, "")) || 0;
    const suffix = target.replace(/[\d]/g, "");
    const step = (ts) => {
      if (!start) start = ts;
      const pct = Math.min((ts - start) / duration, 1);
      const ease = 1 - Math.pow(1 - pct, 3);
      setVal(Math.round(ease * num) + suffix);
      if (pct < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [inView, target]);
  return val || "0";
}

// ── STAT COUNTER COMPONENT (proper component so hook is valid) ──
function StatCounter({ num, suf, label, inView, lightMode }) {
  const counted = useCountUp(num, inView);
  return (
    <span style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontWeight: 700, color: lightMode ? "#FBF7EE" : "#d8b78c", lineHeight: 1 }}>{counted}{suf}</span>
  );
}


function ScrollProgress() {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const update = () => {
      const el = document.documentElement;
      const top = el.scrollTop || document.body.scrollTop;
      const height = el.scrollHeight - el.clientHeight;
      setPct(height > 0 ? (top / height) * 100 : 0);
    };
    window.addEventListener("scroll", update, { passive: true });
    return () => window.removeEventListener("scroll", update);
  }, []);
  return (
    <div style={{ position: "fixed", top: 0, left: 0, right: 0, height: 2, zIndex: 9999, background:"#010000" }}>
      <div style={{ height: "100%", width: `${pct}%`, background: "linear-gradient(90deg, rgba(216,183,140,.6), #d8b78c)", transition: "width .1s linear" }} />
    </div>
  );
}

// ── COUNTDOWN TIMER ──
function CountdownTimer({ targetDate, label = "Days Until Applications Open" }) {
  const calcDays = () => {
    const diff = new Date(targetDate) - new Date();
    return diff <= 0 ? 0 : Math.floor(diff / 86400000);
  };
  const [days, setDays] = useState(calcDays());
  useEffect(() => {
    const i = setInterval(() => setDays(calcDays()), 60000);
    return () => clearInterval(i);
  }, [targetDate]);
  return (
    <div style={{ textAlign: "center", marginBottom: 52 }}>
      <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: "clamp(100px,18vw,180px)", fontWeight: 300, color:"#D9C7A9", lineHeight: 1, letterSpacing: "-0.04em" }}>{days}</div>
      <div style={{ fontFamily: "'Lato', sans-serif", fontSize: 10, letterSpacing: "0.55em", color:"#A48D6E", textTransform: "uppercase", marginTop: 14 }}>{label}</div>
    </div>
  );
}

// ── SHIMMER KEYFRAME INJECTION ──
function ShimmerStyle() {
  useEffect(() => {
    const id = "excalibur-shimmer-style";
    if (document.getElementById(id)) return;
    const s = document.createElement("style");
    s.id = id;
    s.textContent = `
      @keyframes shimmer { 0%,100%{box-shadow:0 0 0 0 rgba(216,183,140,0)} 50%{box-shadow:0 0 18px 2px rgba(216,183,140,.18)} }
      @keyframes modFade { from{;transform:translateX(12px)} to{;transform:translateX(0)} }
      .mod-content { animation: modFade .35s cubic-bezier(.22,1,.36,1) both; }
      .soiree-card { animation: shimmer 3.5s ease-in-out infinite; }
    `;
    document.head.appendChild(s);
  }, []);
  return null;
}

function Breadcrumb({ items, setPage }) {
  if (!items || items.length === 0) return null;
  const textCol = "#D9C7A9";
  const hoverCol = "#A48D6E";
  const lora = "'Lora', Georgia, serif";
  return (
    <div style={{ background: "#100F0C", borderBottom: "1px solid rgba(164,141,110,.12)", padding: "10px 48px" }}>
      <div style={{ maxWidth: 1400, margin: "0 auto", display: "flex", alignItems: "center", gap: 8 }}>
        <span onClick={() => setPage("home")} style={{ fontFamily: lora, fontSize: 10, color: textCol, letterSpacing: "0.12em", textTransform: "uppercase", cursor: "pointer", transition: "color .2s" }}
          onMouseEnter={e => e.target.style.color = hoverCol} onMouseLeave={e => e.target.style.color = textCol}>Home</span>
        {items.map((item, i) => (
          <React.Fragment key={i}>
            <span style={{ fontFamily: lora, fontSize: 9, color: "rgba(164,141,110,.5)" }}>›</span>
            {i === items.length - 1 ? (
              <span style={{ fontFamily: lora, fontSize: 10, color: "#A48D6E", letterSpacing: "0.12em", textTransform: "uppercase" }}>{item.label}</span>
            ) : (
              <span onClick={() => setPage(item.page)} style={{ fontFamily: lora, fontSize: 10, color: textCol, letterSpacing: "0.12em", textTransform: "uppercase", cursor: "pointer", transition: "color .2s" }}
                onMouseEnter={e => e.target.style.color = hoverCol} onMouseLeave={e => e.target.style.color = textCol}>{item.label}</span>
            )}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
}




