// ── SHARED UI ──
const sc = (s) => ({ open: "#d8b78c", soon: "#d8b78c", future: "#d8b78c" }[s]);
const sl = (s) => ({ open: "Applications Open", soon: "Opening Soon", future: "Future Wave" }[s]);

function SBtn({ children, active, onClick }) {
  return (
    <button onClick={onClick} style={{ fontFamily: sans, padding: "9px 22px", background: active ? "rgba(216,183,140,.08)" : "transparent", border: `1px solid ${active ? "rgba(216,183,140,.3)" : "#FBF7EE"}`, color: active ? "#d8b78c" : "#FBF7EE", fontSize: 13, cursor: "pointer", transition: "all .25s", fontWeight: 500 }}>{children}</button>
  );
}
function Eyebrow({ children }) {
  return <p style={{ fontFamily: sans, fontSize: 10, letterSpacing: 5, color:"#010000", fontWeight: 700, marginBottom: 14 }}>{children}</p>;
}
function SectionTitle({ children, center = false }) {
  return <h2 style={{ fontFamily: serif, fontSize: "clamp(26px,4vw,52px)", fontWeight: 600, color:"#d8b78c", lineHeight: 1.05, textAlign: center ? "center" : "left" }}>{children}</h2>;
}
function Sub({ children, center = false }) {
  return <p style={{ fontFamily: serif, fontSize: "clamp(15px,2vw,18px)", color:"#010000", fontStyle: "italic", fontWeight: 600, lineHeight: 1.7, textAlign: center ? "center" : "left", maxWidth: center ? 580 : "100%", margin: center ? "12px auto 0" : "12px 0 0" }}>{children}</p>;
}
function Dot({ solid = false }) {
  return <div style={{ width: 4, height: 4, borderRadius: "50%", background: "#d8b78c", marginTop: 8, flexShrink: 0 }} />;
}
function Li({ children, solid = false }) {
  return (
    <div style={{ display: "flex", gap: 14, marginBottom: 13, alignItems: "flex-start" }}>
      <Dot solid={solid} />
      <span style={{ fontFamily: sans, fontSize: 14, color: solid ? "#FBF7EE" : "#FBF7EE", fontWeight: 300, lineHeight: 1.6 }}>{children}</span>
    </div>
  );
}
function Hr() { return <div style={{ height: 1, background: "linear-gradient(90deg, transparent, #010000 20%, #010000 80%, transparent)" }} />; }
function GoldBar() { return <div style={{ height: 2, background: "#d8b78c" }} />; }
function DimBar() { return <div style={{ height: 2, background:"#010000" }} />; }

// ── NAV ──
function NavLink({ label, active, onClick }) {
  const [hov, setHov] = useState(false);
  return (
    <span onClick={onClick} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
      style={{ fontFamily: "'adobe-garamond-pro', 'Garamond', 'Cormorant Garamond', Georgia, serif", fontWeight: 600, fontSize: 11, letterSpacing: "0.13em", textTransform: "uppercase", color: "#D9C7A9", cursor: "pointer", paddingBottom: 2, borderBottom: active ? `1px solid #D9C7A9` : hov ? "1px solid #D9C7A9" : "1px solid transparent", whiteSpace: "nowrap" }}
    >{label}</span>
  );
}
