const portfolioItems = [
  { n: "01", tab: "Investor Pitch", title: "Venture Finale & Formal Evaluation", tagline: "Public performance. Real feedback. Real faculty and invited panelists. Real stakes.", body: "Students present their final venture concepts before a panel of entrepreneurs, investors, and senior professionals in a formal pitch competition inspired by Shark Tank.\n\nThis is not a classroom showcase. It is a judged venture forum where students are expected to defend their ideas, answer real investor & expert questions, and demonstrate the quality of their leadership thinking under pressure.  Feedback is recorded, and the experience becomes part of the student\u2019s portfolio." },
  { n: "02", tab: "Consulting", title: "Consulting Engagement", tagline: "A professional deliverable with a real client's name on it.", body: "Each student completes a consulting assignment for a local business, producing a deliverable intended for real use by the organization. Not merely a simulation: students work from a real brief, under faculty supervision, toward a real deliverable. Students work in teams, are supervised by faculty, and present their findings directly to the business owner." },
  { n: "03", tab: "Micro-Business", title: "Micro-Business Launch", tagline: "Real customers. Real revenue. Real accountability.", body: "In the Flagship Overview, students do more than pitch ideas \u2014 they <em>forge</em> their dreams. Under assigned mentor guidance, teams\u2019 guidance develop micro-ventures, test them with customers, manage real budgets, create marketing campaigns, pursue revenue, and learn what happens when an idea meets the market.\n\nEvery launch is documented and included in the Excalibur Portfolio, giving students a record of real execution, not just classroom theory." },
  { n: "04", tab: "Externship", title: "Apprenticeship & Externship", tagline: "An internship in the industry sector of the student's choice.", body: "Students complete a 4\u20136 week externship inside a company or professional environment connected to their chosen industry sector, sourced through the Academy\u2019s network of business and industry partners.\n\nThe world often asks young people for experience before giving them the chance to earn it. Excalibur changes that equation. Through selected externships, students observe real work, contribute where appropriate, build professional references, and document the experience as part of their graduation portfolio." },
  { n: "05", tab: "Competition", title: "Competition Record", tagline: "Verified results. Judged by professionals.", body: "Students participate in judged pitch competitions throughout the programs, gaining experience with formal evaluation, structured feedback, and competitive recognition. Results are verified, documented, and included in the portfolio — evidence of performance in a genuine competitive environment." },
  { n: "06", tab: "Portfolio", title: "Bound Graduation Portfolio", tagline: "The complete record. Professionally assembled.", body: "All major analyzes, reports, awards, presentations, and business plans are professionally compiled into a single, coherent portfolio — a physical and digital record of everything a student built, wrote, delivered, and won across the programs. Presented at graduation. Available to support university applications, interviews, and future opportunities." },
  { n: "07", tab: "Recommendations", title: "Faculty Evaluation Letters", tagline: "Letters grounded in direct observation.", body: "Excalibur recommendations are written by lead faculty, top executives, and practitioners who have worked directly with the student and can speak with specificity about performance, judgment, communication, leadership, and growth over time. Not form letters. Observations from professionals who have operated at the highest levels of their fields and observed the student's work directly." },
  { n: "08", tab: "Alumni Network", title: "Alumni Network Access", tagline: "A network that compounds over time.", body: "Graduates gain access to a curated alumni and faculty network that supports continued development, mentorship, and continued mentorship, connection, and opportunity — a community of Excalibur graduates, faculty, and guest speakers that grows with every cohort and program." },
];

function PortfolioFolder({ isMobile }) {
  const [openSet, setOpenSet] = React.useState(new Set([0,1,2,3,4,5,6,7]));
  React.useEffect(() => {
    if (isMobile) setOpenSet(new Set([0]));
    else setOpenSet(new Set([0,1,2,3,4,5,6,7]));
  }, [isMobile]);
  const toggle = (i) => {
    if (!isMobile) return;
    setOpenSet(prev => {
      const next = new Set([i]);
      if (prev.has(i) && prev.size === 1) next.clear();
      return next;
    });
  };
  const isOpen = (i) => openSet.has(i);
  return (
    <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "repeat(4, 1fr)", gap: 2, background: "#010000" }}>
      {portfolioItems.map((item, i) => (
        <div key={i} onClick={() => isMobile && toggle(i)} style={{ background: "#010000", borderTop: `2px solid ${i === 0 ? "#d8b78c" : "rgba(216,183,140,.1)"}`, padding: "28px 24px", cursor: isMobile ? "pointer" : "default", transition: "all .25s" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
            <span style={{ fontFamily: serif, fontSize: 11, color: "#FBF7EE", letterSpacing: "0.1em" }}>{item.n}</span>
            {isMobile && <span style={{ fontFamily: sans, fontSize: 14, color: isOpen(i) ? "#d8b78c" : "#FBF7EE", transition: "transform .25s", display: "inline-block", transform: isOpen(i) ? "rotate(45deg)" : "none" }}>+</span>}
          </div>
          <h4 style={{ fontFamily: serif, fontSize: isMobile ? 22 : 24, fontWeight: 600, color: isOpen(i) ? "#d8b78c" : "#FBF7EE", lineHeight: 1.3, marginBottom: 14 }}>{item.title}</h4>
          {isOpen(i) && (
            <div className={isMobile ? "mod-content" : ""}>
              <p style={{ fontFamily: serif, fontSize: 13, color: "#FBF7EE", fontStyle: "italic", lineHeight: 1.5, marginBottom: 12 }}>{item.tagline}</p>
              <div style={{ fontFamily: sans, fontSize: 13, lineHeight: 1.8, color: "#FBF7EE", fontWeight: 300 }}>
                {item.body.split('\n\n').map((para, pi) => (
                  <p key={pi} style={{ marginBottom: pi < item.body.split('\n\n').length - 1 ? 12 : 0 }} dangerouslySetInnerHTML={{ __html: para }} />
                ))}
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

// ── PORTFOLIO INDEX — WHITE LUXURY ──
function PortfolioIndexWhite({ isMobile, setPage, images }) {
  const [active, setActive] = useState(0);
  const item = portfolioItems[active];
  return (
    <div style={{ maxWidth: 1100, margin: "0 auto", padding: isMobile ? "32px 24px 52px" : "48px 80px 72px" }}>
      {isMobile ? (
        // Mobile — vertical accordion
        <div style={{ display: "flex", flexDirection: "column", gap: 0, background: "#34150F" }}>
          {portfolioItems.map((it, i) => (
            <div key={i} style={{ borderBottom: "1px solid rgba(217,199,169,.15)" }}>
              <div onClick={() => setActive(active === i ? -1 : i)} style={{ padding: "18px 0", display: "flex", justifyContent: "space-between", alignItems: "center", cursor: "pointer" }}>
                <div style={{ display: "flex", gap: 16, alignItems: "center" }}>
                  <span style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 13, color:"rgba(217,199,169,.4)", fontStyle: "italic" }}>{it.n}</span>
                  <span style={{ fontFamily: "'Bodoni Cyrillic', 'Bodoni MT', serif", fontSize: 16, fontWeight: 400, color: "#D9C7A9", letterSpacing: "0.04em", textTransform: "uppercase" }}>{it.title}</span>
                </div>
                <span style={{ fontFamily: sans, fontSize: 18, color: active === i ? "#D9C7A9" : "rgba(217,199,169,.3)", transform: active === i ? "rotate(45deg)" : "none", transition: "transform .25s", display: "inline-block" }}>+</span>
              </div>
              {active === i && (
                <div style={{ paddingBottom: 20, paddingLeft: 30 }}>
                  <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 13, color:"#D9C7A9", fontStyle: "italic", marginBottom: 8 }}>{it.tagline}</p>
                  <div style={{ fontFamily: sans, fontSize: 13, color:"#E4D5C1", fontWeight: 300, lineHeight: 1.8 }}>
                    {it.body.split('\n\n').map((para, pi) => (
                      <p key={pi} style={{ marginBottom: pi < it.body.split('\n\n').length - 1 ? 12 : 0 }} dangerouslySetInnerHTML={{ __html: para }} />
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}
          {images && images.length > 0 && (
            <div style={{ position: "relative", height: 320, padding: "32px 24px" }}>
              <div style={{ position: "relative", width: "78%", height: 200 }}>
                <img src={images[0]} alt="" style={{ position: "absolute", top: 0, left: 0, width: "100%", height: "100%", objectFit: "cover", boxShadow: "0 24px 48px rgba(0,0,0,.55)" }} />
                <img src={images[1]} alt="" style={{ position: "absolute", bottom: -36, right: -48, width: "62%", height: "62%", objectFit: "cover", boxShadow: "0 28px 56px rgba(0,0,0,.6)", border: "1px solid rgba(217,199,169,.25)" }} />
              </div>
            </div>
          )}
        </div>
      ) : (
        // Desktop — index left, detail center, photos right (true third column)
        <div style={{ display: "grid", gridTemplateColumns: images && images.length > 0 ? "280px 1fr 300px" : "280px 1fr", gap: 0, border: "1px solid rgba(217,199,169,.2)" }}>
          {/* Left  -  index */}
          <div style={{ borderRight: "1px solid rgba(217,199,169,.2)", background: "#34150F" }}>
            {portfolioItems.map((it, i) => (
              <div key={i} onClick={() => setActive(i)} style={{
                padding: "18px 28px", cursor: "pointer", display: "flex", gap: 16, alignItems: "center",
                background: active === i ? "#D9C7A9" : "transparent",
                borderLeft: active === i ? "2px solid #D9C7A9" : "2px solid transparent",
                borderBottom: "1px solid rgba(217,199,169,.15)", transition: "all .2s",
              }}>
                <span style={{ fontFamily: "'Bodoni Cyrillic', 'Bodoni MT', serif", fontSize: 16, fontWeight: 400, color: active === i ? "#34150F" : "#D9C7A9", lineHeight: 1.2, transition: "all .2s", letterSpacing: "0.04em", textTransform: "uppercase" }}>{it.title}</span>
              </div>
            ))}
          </div>
          {/* Center  -  detail panel */}
          <div style={{ padding: "44px 52px", background: "#34150F", display: "flex", flexDirection: "column", justifyContent: "space-between", minHeight: 360, borderRight: images && images.length > 0 ? "1px solid rgba(217,199,169,.2)" : "none" }}>
            <div>
              <div style={{ display: "flex", alignItems: "baseline", gap: 20, marginBottom: 20 }}>
                <h3 style={{ fontFamily: "'Bodoni Cyrillic', 'Bodoni MT', serif", fontSize: 52, fontWeight: 400, color:"#D9C7A9", lineHeight: 1.0, letterSpacing: "0.04em", textTransform: "uppercase" }}>{item.title}</h3>
              </div>
              <div style={{ width: 36, height: 1, background: "linear-gradient(90deg, rgba(217,199,169,.5), transparent)", marginBottom: 20 }} />
              <p style={{ fontFamily: "'Cormorant Garamond', Georgia, serif", fontSize: 22, color:"#D9C7A9", fontStyle: "italic", marginBottom: 24, lineHeight: 1.4, fontWeight: 400 }}>{item.tagline}</p>
              <div style={{ fontFamily: sans, fontSize: 14, color:"#E4D5C1", fontWeight: 300, lineHeight: 1.9, maxWidth: 560 }}>
                {item.body.split('\n\n').map((para, pi) => (
                  <p key={pi} style={{ marginBottom: pi < item.body.split('\n\n').length - 1 ? 14 : 0 }} dangerouslySetInnerHTML={{ __html: para }} />
                ))}
              </div>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 36, paddingTop: 24, borderTop: "1px solid rgba(217,199,169,.15)" }}>
              <span style={{ fontFamily: sans, fontSize: 9, letterSpacing: "0.3em", color:"rgba(217,199,169,.5)", textTransform: "uppercase", fontWeight: 700 }}>{active + 1} of {portfolioItems.length}</span>
              <div style={{ display: "flex", gap: 8 }}>
                <button onClick={() => setActive(a => Math.max(0, a - 1))} disabled={active === 0} style={{ background: "none", border: "1px solid rgba(217,199,169,.3)", color: active === 0 ? "rgba(217,199,169,.2)" : "#D9C7A9", width: 36, height: 36, cursor: active === 0 ? "default" : "pointer", fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", transition: "all .2s" }}>‹</button>
                <button onClick={() => setActive(a => Math.min(portfolioItems.length - 1, a + 1))} disabled={active === portfolioItems.length - 1} style={{ background: "none", border: "1px solid rgba(217,199,169,.3)", color: active === portfolioItems.length - 1 ? "rgba(217,199,169,.2)" : "#D9C7A9", width: 36, height: 36, cursor: active === portfolioItems.length - 1 ? "default" : "pointer", fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", transition: "all .2s" }}>›</button>
              </div>
            </div>
          </div>
          {/* Right  -  layered 3D photo stack, same table background */}
          {images && images.length > 0 && (
            <div style={{ background: "#34150F", display: "flex", alignItems: "center", justifyContent: "center", padding: "32px 28px" }}>
              <div style={{ position: "relative", width: "100%", height: 280 }}>
                <img src={images[0]} alt="" style={{ position: "absolute", top: "-105px", left: 0, width: "82%", height: "200px", objectFit: "cover", boxShadow: "0 30px 60px rgba(0,0,0,.6)", transform: "rotate(-2deg)" }} />
                <img src={images[1]} alt="" style={{ position: "absolute", top: "59.6px", right: 0, width: "62%", height: "300px", objectFit: "cover", boxShadow: "0 34px 64px rgba(0,0,0,.65)", border: "6px solid #34150F", transform: "rotate(2deg)" }} />
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── FOOTER ──
function Footer({ setPage }) {
  const isMobile = useIsMobile();
  const allLinks = [["HOME","home"],["THE ACADEMY","about"],["OUR PROGRAMS","programs"],["CURRICULUM","curriculum"],["FACULTY","faculty"],["THE ARENA","beyond"],["ADMISSIONS","apply"],["CONTACT","contact"],["EVENTS","events"]];
  return (
    <footer style={{ background: "#34150F", borderTop: "1px solid rgba(188,166,150,.12)" }}>
      {/* Brand + Nav */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: isMobile ? "48px 24px 32px" : "60px 60px 40px", borderBottom: "1px solid rgba(188,166,150,.1)", display: "flex", flexDirection: isMobile ? "column" : "row", justifyContent: "space-between", alignItems: isMobile ? "flex-start" : "flex-end", gap: 32 }}>
        <div onClick={() => setPage("home")} style={{ cursor: "pointer" }}>
          <div style={{ fontFamily: "'Forum', serif", fontSize: isMobile ? 22 : 34, color: "#BCA696", letterSpacing: "0.12em", textTransform: "uppercase", lineHeight: 1, marginBottom: 10 }}>Excalibur Academy</div>
          <div style={{ fontFamily: serif, fontSize: isMobile ? 13 : 15, color: "#BCA696", fontStyle: "italic", fontWeight: 300, letterSpacing: "0.03em" }}>Forging the leaders of tomorrow</div>
        </div>
        <nav style={{ display: "flex", gap: isMobile ? 16 : 28, flexWrap: "wrap", alignItems: "center" }}>
          {allLinks.map(([l, p]) => (
            <span key={p} onClick={() => setPage(p)} style={{ fontFamily: "'Lora', Georgia, serif", color: "#BCA696", fontSize: 10, cursor: "pointer", letterSpacing: "0.3em", fontWeight: 700, textTransform: "uppercase", transition: "color .2s", whiteSpace: "nowrap" }} onMouseEnter={e => e.target.style.color = "#E4D5C1"} onMouseLeave={e => e.target.style.color = "#BCA696"}>{l}</span>
          ))}
        </nav>
      </div>
      {/* Emails + Legal */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: isMobile ? "36px 24px" : "44px 60px", borderBottom: "1px solid rgba(188,166,150,.07)" }}>
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr 1fr", gap: isMobile ? 28 : 0 }}>
          {/* Business info */}
          <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
            <span style={{ fontFamily: eyebrow_font, fontSize: 11, color: "#BCA696", letterSpacing: "0.25em", textTransform: "uppercase", fontWeight: 600, marginBottom: 4 }}>Excalibur Academy LLC</span>
            <span style={{ fontFamily: serif, fontSize: 18, color: "#BCA696", fontStyle: "italic", letterSpacing: "0.05em" }}>Orange County, California</span>
          </div>
          {/* Applications email */}
          <div style={{ display: "flex", flexDirection: "column", gap: 5, borderLeft: isMobile ? "none" : "1px solid rgba(188,166,150,.15)", paddingLeft: isMobile ? 0 : 48 }}>
            <span style={{ fontFamily: eyebrow_font, fontSize: 11, color: "#BCA696", letterSpacing: "0.25em", textTransform: "uppercase", fontWeight: 800, marginBottom: 4 }}>ADMISSIONS</span>
            <a href="mailto:admissions@excaliburacademy.org" style={{ fontFamily: serif, fontSize: 18, color: "rgba(228, 214, 193, 1)", textDecoration: "none", letterSpacing: "0.05em", fontStyle: "italic", transition: "color .2s" }} onMouseEnter={e => e.target.style.color = "#E4D5C1"} onMouseLeave={e => e.target.style.color = "#BCA696"}>admissions@excaliburacademy.org</a>
          </div>
          {/* Support email */}
          <div style={{ display: "flex", flexDirection: "column", gap: 5, borderLeft: isMobile ? "none" : "1px solid rgba(188,166,150,.15)", paddingLeft: isMobile ? 0 : 48 }}>
            <span style={{ fontFamily: eyebrow_font, fontSize: 11, color: "#BCA696", letterSpacing: "0.25em", textTransform: "uppercase", fontWeight: 600, marginBottom: 4 }}>GENERAL INQUIRIES</span>
            <a href="mailto:support@excaliburacademy.org" style={{ fontFamily: serif, fontSize: 18, color: "rgba(228, 214, 193, 1)", textDecoration: "none", letterSpacing: "0.05em", fontStyle: "italic", transition: "color .2s" }} onMouseEnter={e => e.target.style.color = "#E4D5C1"} onMouseLeave={e => e.target.style.color = "#BCA696"}>support@excaliburacademy.org</a>
          </div>
        </div>
      </div>
      {/* Copyright */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: isMobile ? "20px 24px" : "20px 60px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 8 }}>
        <p style={{ fontFamily: sans, fontSize: 9, color: "#BCA696", letterSpacing: "0.08em", textTransform: "uppercase" }}>© 2026 Excalibur Academy LLC · Orange County, California</p>
      </div>
    </footer>
  );
}


