            <p style={{ fontFamily: "Times, serif", color: "#A48D6E", fontSize: 13, marginTop: 20, letterSpacing: "0.26em", fontWeight: 500, textTransform: "uppercase" }}>ADMISSIONS@EXCALIBURACADEMY.ORG</p>
