function FacultyProfilePage({ slug, setPage }) {
  const isMobile = useIsMobile();
  const f = facultyProfiles[slug];

  if (!f) {
    return (
      <div style={{ background: "#010000", minHeight: "100vh", paddingTop: 120, textAlign: "center" }}>
        <p style={{ fontFamily: sans, color: "#FBF7EE", fontSize: 14 }}>Faculty profile not found.</p>
        <button onClick={() => setPage("faculty")} style={{ fontFamily: sans, color: "#FBF7EE", background: "transparent", border: "none", cursor: "pointer", fontSize: 13, marginTop: 16 }}>← Back to Faculty Directory</button>
      </div>
    );
  }

  return (
    <div style={{ background: "#010000", paddingTop: 0 }}>

      {/* Hero  -  photo beside info, no crop */}
      <div style={{ background: "#010000", borderBottom: "1px solid rgba(216,183,140,.1)" }}>
        <button onClick={() => setPage("faculty")} style={{ display: "block", padding: isMobile ? "16px 20px" : "20px 60px", fontFamily: sans, background: "transparent", border: "none", color:"#FBF7EE", fontSize: 11, cursor: "pointer", letterSpacing: "0.15em" }}>← OUR FACULTY</button>
        <div style={{ display: "grid", gridTemplateColumns: isMobile ? "1fr" : "360px 1fr", maxWidth: 1100, margin: "0 auto", padding: isMobile ? "0 0 40px" : "0 40px 64px", gap: isMobile ? 28 : 64, alignItems: "start" }}>
          {/* Photo  -  full show, no crop */}
          <div style={{ overflow: "hidden", border: "1px solid rgba(216,183,140,.12)" }}>
            <img src={f.img} alt={f.name} style={{ width: "100%", height: "auto", objectFit: "contain", display: "block" }} onError={e => e.target.style.display = "none"} />
          </div>
          {/* Info */}
          <div style={{ padding: isMobile ? "0 24px" : "32px 0 0" }}>
            <p style={{ fontFamily: eyebrow_font, fontSize: 10, letterSpacing: "0.4em", color:"#FBF7EE", fontWeight: 600, textTransform: "uppercase", marginBottom: 12 }}>{f.role}</p>
            <h1 style={{ fontFamily: serif, fontSize: isMobile ? "clamp(32px,7vw,48px)" : "clamp(40px,4vw,60px)", fontWeight: 600, color:"#d8b78c", lineHeight: 1.05, marginBottom: 16 }}>{f.name}</h1>

            <p style={{ fontFamily: serif, fontSize: isMobile ? 15 : 18, color:"#FBF7EE", fontStyle: "italic", lineHeight: 1.6 }}>{f.headline}</p>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 24 }}>
              {f.tags.map((t, i) => (
                <span key={i} style={{ fontFamily: sans, fontSize: 9, color:"#FBF7EE", letterSpacing: "0.1em", border: "1px solid rgba(216,183,140,.2)", padding: "3px 10px", textTransform: "uppercase" }}>{t}</span>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div style={{ maxWidth: 1100, margin: "0 auto", display: "grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 320px", gap: isMobile ? 0 : 2, background: "#010000" }}>

        {/* Bio  -  left */}
        <div style={{ background: "#010000", padding: isMobile ? "48px 28px" : "72px 72px" }}>
          {f.paras.map((para, i) => (
            <p key={i} style={{ fontFamily: sans, fontSize: isMobile ? 14 : 15, lineHeight: 1.95, color: "#FBF7EE", fontWeight: 300, marginBottom: 22 }}>{para}</p>
          ))}
          <div style={{ marginTop: 48 }}>
            {f.linkedin ? (
              <a href={f.linkedin} target="_blank" rel="noopener noreferrer" style={{ display: "inline-block", fontFamily: sans, background: "transparent", color: "#FBF7EE", padding: "13px 0", fontSize: 11, fontWeight: 700, letterSpacing: "0.18em", textTransform: "uppercase", textDecoration: "none", borderBottom: `1px solid #d8b78c` }}>Connect on LinkedIn →</a>
            ) : !["Alexander Milstein", "Anastasia Milstein", "Amina Abdulaeva"].includes(f.name) ? (
              <button onClick={() => setPage("apply")} style={{ fontFamily: sans, background: "#d8b78c", color:"#010000", padding: "13px 36px", fontSize: 11, fontWeight: 700, letterSpacing: "0.18em", textTransform: "uppercase", border: "none", cursor: "pointer" }}>Apply to Study Under {f.name.split(" ")[0]} →</button>
            ) : null}
          </div>
        </div>

        {/* Selected Credentials sidebar  -  right */}
        <div style={{ background: "#010000", padding: isMobile ? "40px 28px" : "72px 40px" }}>
          {!f.linkedin && (<>
          <p style={{ fontFamily: sans, fontSize: 10, letterSpacing: "0.35em", color:"#FBF7EE", fontWeight: 600, textTransform: "uppercase", marginBottom: 24 }}>Selected Credentials</p>
          <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
            {f.credentials.map((cr, i) => (
              <div key={i} style={{ display: "flex", gap: 14, padding: "14px 0", borderBottom: "1px solid rgba(0,0,0,.07)", alignItems: "flex-start" }}>
                <div style={{ width: 4, height: 4, borderRadius: "50%", background: "#d8b78c", flexShrink: 0, marginTop: 7 }} />
                <span style={{ fontFamily: sans, fontSize: 12, color:"#010000", fontWeight: 300, lineHeight: 1.65 }}>{cr}</span>
              </div>
            ))}
          </div>
          <div style={{ marginTop: 40 }}>
            <p style={{ fontFamily: sans, fontSize: 10, letterSpacing: "0.35em", color:"#010000", fontWeight: 600, textTransform: "uppercase", marginBottom: 16 }}>Expertise</p>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
              {f.tags.map((t, i) => (
                <span key={i} style={{ fontFamily: sans, fontSize: 9, color:"#010000", letterSpacing: "0.1em", border: "1px solid rgba(216,183,140,.15)", padding: "4px 10px", textTransform: "uppercase" }}>{t}</span>
              ))}
            </div>
          </div>
          </>)}
          <div style={{ marginTop: f.linkedin ? 0 : 40, paddingTop: f.linkedin ? 0 : 32, borderTop: f.linkedin ? "none" : "1px solid rgba(216,183,140,.08)" }}>
            <p style={{ fontFamily: sans, fontSize: 10, letterSpacing: "0.35em", color:"#010000", fontWeight: 600, textTransform: "uppercase", marginBottom: 16 }}>Also Meet</p>
            {Object.values(facultyProfiles).filter(p => p.name !== f.name).slice(0, 3).map((p, i) => (
              <div key={i} onClick={() => setPage(`faculty:${p.name.toLowerCase().replace(/ /g, "-")}`)} style={{ display: "flex", gap: 12, marginBottom: 14, cursor: "pointer", alignItems: "center" }}>
                <div style={{ width: 40, height: 40, overflow: "hidden", border: "1px solid rgba(216,183,140,.15)", flexShrink: 0 }}>
                  <img src={p.img} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center top" }} />
                </div>
                <div>
                  <p style={{ fontFamily: serif, fontSize: 13, color:"#010000" }}>{p.name}</p>
                  <p style={{ fontFamily: sans, fontSize: 9, color:"#010000", letterSpacing: "0.08em" }}>{p.role}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

