  const ph = ["https://i.pinimg.com/1200x/34/14/af/3414af53e9e837988727df0d86b90fba.jpg","https://i.pinimg.com/736x/b3/36/92/b3369292b572103f69aba9176ae3354b.jpg","https://i.pinimg.com/1200x/52/7c/7c/527c7c75c4daeb052fdaffc708a2b964.jpg","https://i.pinimg.com/736x/d9/71/40/d9714059c897aa42ff124dbb35c1d1cf.jpg","https://i.pinimg.com/736x/d8/fb/97/d8fb97d5e70d7147e722f2df23d6857e.jpg","https://i.imgur.com/V6jNVu8.jpeg","https://i.imgur.com/6GAZVBw.jpeg","https://i.imgur.com/s0eJfeQ.jpeg","https://i.imgur.com/CHrzSm0.jpeg","https://i.imgur.com/h6XGZ6s.jpeg","https://i.imgur.com/BBfsu4x.jpeg","https://i.imgur.com/3PUR6cG.jpeg"];

  const fMods = [
    { n:"01", title:"Public Speaking & Leadership Communication", tagline:"Presence. Persuasion. Authority.", sub:"Senior Public Speaking Instructor · Every session · All 14 weeks (Foundation) · All 16 weeks (Venture)",
      body:"Every serious path in leadership begins with the ability to stand before others and speak with clarity, conviction, and control, clarity, and composure. Students work from fundamentals through to Aristotelian rhetoric, narrative architecture, and the ability to hold attention without spectacle. By semester end, students complete repeated individual speaking exercises, recorded practice, and faculty feedback.",
      learn:["Voice mechanics — projection, pacing, tone variation, and the power of silence","Physical presence — posture, eye contact, and gesture that conveys authority","Aristotle\'s three modes: ethos, pathos, logos","Narrative architecture — tension, clarity, one unforgettable idea","Impromptu speaking, advanced rhetoric, debate and Q&A defense","Executive communication — briefing a team, presenting to faculty, guests, and professional audiences"] },
    { n:"02", slug:"financial-literacy", title:"Financial Literacy & Business Acumen", tagline:"Understand capital. Think like an owner.",
      body:"Financial literacy is one of the few skills every student will use for the rest of their life. Yet while traditional education teaches mathematics, history, and science, few students ever learn how money works, how businesses create value, or how founders, executives, and families make financial decisions.\n\nFinancial Literacy & Business Acumen introduces students to the principles that govern money, markets, entrepreneurship, and value creation. Students learn to read a business the way founders, executives, and investors do — not as a set of abstract numbers, but as a living system of decisions, trade-offs, incentives, opportunities, trade-offs, and consequences.",
      learn:["Revenue, margin, and profit — and why strong sales do not always mean a strong business","How to read a profit-and-loss statement, balance sheet, and cash flow statement","Cash flow — why timing, expenses, and working capital can make or break a business","Unit economics — customer acquisition cost, lifetime value, contribution margin, and break-even point","Pricing strategy — cost-plus, value-based, competitive, and dynamic pricing","Compound interest — how money grows, and why starting early changes the long-term math","Equity and ownership — how a company is divided, diluted, valued, and financed","How investors evaluate businesses — revenue, margins, EBITDA, multiples, comparable companies, and growth potential","Financial decision-making — how founders decide what is worth building, funding, cutting, or scaling","Applied financial briefing — students analyze a real, local, public, or case-based business using public information, pricing, market observation"] },
    { n:"03", slug:"business-models", title:"Business Model Analysis", tagline:"Break down any business. Find the logic.", sub:"Case Studies: Netflix · Apple · Amazon · Airbnb · Tesla",
      body:"Every successful company operates according to a business model. Students learn to break down any company — from a neighborhood café to a global technology firm — and explain, with clarity and precision, how it generates revenue, where costs concentrate, what advantage protects it, and what single vulnerability could weaken or collapse the model. They learn to ask the questions that actually matter: What drives demand? What scales? What breaks under pressure? What protects the margin?\n\nThe module culminates in a live deconstruction exercise: students analyze businesses and present their findings in Investor Briefing format. The result is not theory — but fluency. Students graduate able to analyze, challenge, and understand a wide range of businesses and industries.",
      learn:["The eight business models: subscription, marketplace, direct-to-consumer, advertising, franchise, freemium, professional services, hardware-plus-consumable","How to identify a company's core value proposition and revenue capture mechanism","Competitive advantage analysis — cost leadership, differentiation, focus, network effects","Vulnerability mapping — identifying the greatest strategic risk in any business model","Investor Briefing format — how analysts present company analysis to investment committees","Case studies: Netflix, Apple, Amazon, Airbnb, Tesla and other iconic business model evolution","Business model disruption — how it happens and why incumbents fail to respond"] },
    { n:"04", slug:"art-of-selling", title:"The Art of Selling & Marketing", tagline:"Persuasion with integrity. Influence with discipline.",
      body:"From brand strategy and customer acquisition to capital raising and executive negotiation, business depends on the ability to communicate value clearly. This module treats it as a core life skill — training students in applied persuasion as it actually happens: unscripted, high-stakes, and consequential.\n\nNo matter how strong an idea, product, service, or venture may be, it has little value if nobody understands why it matters. Sales and marketing sit at the center of every successful business because they determine how value is communicated and adopted.\n\nThis module teaches students to listen carefully, understand what another person actually needs, articulate value with confidence, and move a conversation toward a clear decision.\n\nThe best salespeople are not the loudest voices in the room. They are the sharpest listeners, the clearest thinkers, the most precise communicators and human psychologists.",
      learn:["Consultative selling: asking, listening, diagnosing, and proposing with precision","Customer psychology: why people buy, hesitate, trust, compare, and decide","Branding, positioning, and differentiation: making an offer distinct and memorable","Sales conversations: opening, discovery, presentation, objection handling, and closing","Cold outreach, warm introductions, referrals, and professional follow-up strategy","Marketing channels, customer acquisition, and growth campaigns","Messaging, offers, copywriting, and persuasive communication","Paid advertising fundamentals: audiences, budgets, platforms, creative testing, and performance metrics","Live role-play, recorded feedback, and campaign presentations before faculty and coaches"] },
    { n:"05", slug:"capital-markets", title:"Capital Markets, Investing & Wealth Management", tagline:"Understanding capital, risk, and market behavior.",
      body:"Most people are affected by financial markets for their entire lives without ever being taught how they actually work. This module builds market literacy from the ground up — how global exchanges operate, how companies are valued, how capital moves, how investors think about risk, and how wealth is built, protected, and allocated over time.\n\nStudents study the major institutions and forces that shape markets: the New York Stock Exchange, NASDAQ, the London Stock Exchange, global currency markets, the S&P 500, interest rates, inflation, investor psychology, and the movement of capital between public markets, private equity, venture capital, and digital assets and emerging financial technologies.\n\nThey learn the language of markets — bull and bear markets, equities, bonds, indexes, currencies, liquidity, volatility, valuation, and diversification, how crypto works as both a financial and technological phenomenon — and how to read financial news with intelligence rather than reaction.\n\nThe module introduces the habits of serious investors: thesis development, fundamental analysis, risk awareness, portfolio construction, emotional discipline, long-term thinking, and the ability to separate knowledge from impulse.\n\nStudents examine historical portfolios and strategies used by major investors, compare different approaches to stock market investing, and study why disciplined allocation matters more than chasing the next trade.\n\nThrough portfolio simulations, paper trading, market briefings, and investment thesis exercises, students see how quickly emotion can distort judgment — and why serious wealth is built through knowledge, patience, structure, and discipline.",
      learn:["How global exchanges work: NYSE, NASDAQ, London Stock Exchange, market makers, liquidity, order types, and price discovery","The language of markets: bull markets, bear markets, stocks, bonds, indexes, currencies, volatility, liquidity, and market cycles","How to read the financial press: earnings reports, market commentary, analyst notes, economic headlines, and investor letters","What drives stock prices: earnings, growth, margins, valuation, interest rates, sentiment, competitive advantage, and future expectations","How to read a public company: revenue, margins, EPS, P/E ratios, revenue multiples, growth rates, and valuation logic","Major market indexes: S&P 500, S&P 500, NASDAQ Composite, Dow Jones Industrial Average, and what each actually represents","Risk and return: diversification, position sizing, time horizon, volatility, drawdowns, and portfolio construction","Investment strategies: value investing, growth investing, index investing, dividend investing, thematic investing, and long-term compounding","Historical portfolios and investor case studies: how major investors built theses, managed risk, and allocated capital over time","Investor psychology: loss aversion, confirmation bias, overconfidence, herd behavior, patience, and emotional discipline","Macroeconomic forces: how interest rates, inflation, employment, Fed policy, currency movements, and global events affect markets","Venture capital, private equity, and startup investing: how private capital is raised, deployed, and returned","Digital assets: blockchain mechanics, tokenomics, custody, regulation, risk, and the distinction between innovation and speculation","Wealth management fundamentals: asset allocation, compounding, tax awareness, liquidity, estate planning, trusts, and long-term family wealth structures","Portfolio simulation, paper trading, and investment thesis exercises using real market data","How investors evaluate companies, opportunities, risks, timing, and whether an investment belongs in a diversified portfolio"] },
    { n:"06", slug:"leadership", title:"Leadership, Influence & Decision-Making", tagline:"Lead through judgment, trust, and earned authority.", sub:"Signature: CEO Crisis Simulation",
      body:"Leadership is tested most clearly under pressure: in moments of pressure, uncertainty, disagreement, and responsibility. Leadership is not a title. It is the ability to earn trust, make decisions, communicate clearly, and bring people with you when the path is uncertain.\n\nThis module teaches the disciplines behind effective leadership: building credibility, reading people, managing conflict, making decisions with incomplete information, communicating direction, and remaining composed when others are looking for judgment. Students examine the power of influence, explore emotional intelligence, study team dynamics, and practice the habits that separate genuine leaders from those who merely occupy positions.\n\nThrough case studies, live exercises, and the signature CEO Crisis Simulation, students learn that leadership is not performance. It is responsibility made visible.",
      learn:["The five forms of power: legitimate, reward, coercive, expert, and referent — and which forms create lasting authority","Emotional intelligence: self-awareness, self-regulation, empathy, motivation, and social skill","Decision-making under uncertainty — frameworks for consequential choices with incomplete information","Conflict resolution: how to navigate disagreement, preserve trust, and move a group forward","Team dynamics: stages of team development, leadership roles, and the habits of high-performing teams","Influence without title: how credibility, consistency, timing, and judgment shape whether people follow","Executive communication: how to brief, align, persuade, correct, and give direction clearly","Crisis communication: how to lead when things are going wrong, how to communicate when circumstances change quickly and the room needs clarity","CEO Crisis Simulation: a live exercise where students lead a fictional company through a fast-moving business challenge","Mental fortitude: staying composed, focused, and decisive under pressure"] },
    { n:"07", slug:"negotiation-psychology", title:"Negotiation & Human Psychology", tagline:"Read the room. Understand people. Shape the outcome.", sub:"Live Simulations: Deals · Equity · Partnerships · High-Stakes Conversations",
      body:"Every serious arena — business, politics, media, family enterprise, startups, law, diplomacy, and leadership — is built on negotiation. Behind every major deal is a conversation where someone read the room better, understood the incentives faster, and knew when to push, pause, concede, or walk away.\n\nThis module brings students inside the psychology of influence: the kind of conversations they recognize from boardroom dramas like Succession, agency-room persuasion in Mad Men, hedge-fund strategy in Billions, courtroom and dealmaking tension in Suits, and the micro-expression reading made famous by Lie to Me. Students learn leverage, incentives, trust, status, timing, silence, emotion, and command of the conversation.\n\nThey study famous corporate and political negotiations, iconic business deals, founder-investor conversations, salary negotiations, partnership disputes, media power plays, and moments where the outcome depended on reading people correctly. Students learn how trust is built, how emotions show through body language, how hesitation reveals uncertainty, and how skilled negotiators move a conversation without making it feel forced.\n\nThrough live simulations inspired by real business and political scenarios, students practice staying composed, asking sharper questions, detecting hesitation, recognizing micro-signals, building leverage, and reaching agreements that are clear, credible, and lasting. The goal is to understand people between the lines — where they are strong, what pain points are shaping their decisions, what they will not say directly, and how to move a conversation forward with clarity, leverage, and judgment — toward a clear, credible, and durable outcome.",
      learn:["Famous negotiations and deals: corporate mergers, founder-investor terms, political agreements, media power plays, and partnership breakdowns","Boardroom negotiation: how executives, founders, investors, and advisors frame offers, defend positions, and shift leverage","The psychology of decision-making: why people say yes, hesitate, resist, trust, or walk away","Reading the room: tone, pacing, silence, posture, eye contact, hesitation, confidence, and emotional shifts","Micro-signals and nonverbal communication: how small changes in expression, body language, and rhythm reveal uncertainty or conviction","Leverage and timing: when to speak, when to wait, when to ask, when to concede, and when to leave the table","Interest-based negotiation: separating what people say they want from what they actually need","BATNA, ZOPA, anchoring, concessions, and walk-away discipline — the tools behind every serious negotiation","Power, credibility, and status: how authority, reputation, money, information, scarcity, and relationships shape the room","Influence principles: reciprocity, social proof, framing, contrast, commitment, and credibility","Trust-building: how discretion, consistency, empathy, and competence create long-term relationship capital","Live simulations: negotiations, equity split, investor terms, co-founder conflict, client pitch, partnership deal, and crisis conversation"] },
    { n:"08", title:"Legal Foundations for Founders", tagline:"Know what you\'re signing before you sign it.", sub:"Outside Specialist — Practicing Attorney with Startup Experience",
      body:"Most founders do not make legal mistakes because they are careless. They make them because they do not yet know what can go wrong: the wrong entity, unclear ownership, missing IP protection, weak founder agreements, careless contracts, or terms they did not fully understand until it was too late.\n\nThis module gives students the legal literacy every young founder needs before building, partnering, raising money, or signing anything consequential. It is a practical introduction to the structures, documents, and decisions that shape the first years of a company.\n\nStudents learn how companies are formed, how ownership is divided, how intellectual property is protected, how contracts create obligations, and why the details of founder agreements, NDAs, equity terms, and term sheets matter before a serious business relationship begins.",
      learn:["Business entity types: LLC, C-corp, S-corp, sole proprietorship, and when each structure makes sense","Equity structure: ownership splits, dilution, vesting schedules, cliff periods, and what happens when a co-founder leaves","Founder agreements: roles, responsibilities, equity, decision rights, vesting, IP assignment, and dispute prevention","Intellectual property: trademarks, copyrights, patents, trade secrets, ownership, and protection of what students build","Contracts and NDAs: what makes an agreement binding, what clauses create risk, and what should never be signed casually","Employment and contractor basics: IP assignment, confidentiality, compensation, and early-team agreements","Term sheet basics: valuation, equity, liquidation preference, control rights, investor protections, and the clauses founders must understand","Cap tables: how ownership changes over time and why early mistakes become expensive later","How to work with a lawyer: what to ask, what to understand yourself, and when professional legal guidance is necessary"] },
    { n:"09", title:"Personal Finance & Wealth Building", tagline:"Earning money is only the beginning.", sub:"Academy Dean + Outside Specialist (Financial Planner or Wealth Advisor)",
      body:"Most students are told to work hard, get into a good university, and eventually earn a strong income. Very few are taught what to do with money once they have it — whether that income comes from a summer job, part-time work, freelance projects, a first salary, or profit from a business they build.\n\nThis module introduces students to the principles of personal finance and long-term wealth building. They learn how financially disciplined people think about income, spending, saving, taxes, credit, debt, investing, real estate, compounding, risk, liquidity, and long-term family financial planning. The goal is not to turn students into financial advisors. It is to give them the literacy and judgment to manage money responsibly, ask better questions, avoid common mistakes, and start thinking about wealth with maturity.\n\nStudents examine the difference between earning income and building wealth — and why early decisions, even small ones, can create a structural advantage over time.",
      learn:["Income management: how to handle money responsibly, whether it comes from a summer job, part-time work, freelance income, business profit, or a future full-time salary","Budgeting and cash management: building a personal budget, tracking spending, and understanding where money actually goes","Credit building: credit scores, credit cards, utilization, payment history, responsible borrowing, and how early mistakes can affect future options","Tax fundamentals: how income tax works, why tax planning matters, and how employees, contractors, founders, and business owners are taxed differently","Compound interest: how money grows over time, applied to a teenager's timeline with real numbers","Retirement accounts — Roth IRA, traditional IRA, and 401(k) basics: what each account is, how they differ, and why starting early matters","Debt: good debt vs. bad debt, interest rates, credit cards, student loans, and how borrowing can help or damage wealth creation","Real estate as a wealth vehicle: appreciation, leverage, rental income, cash flow, and why many wealthy families own property","Insurance and protection: why wealth must be protected, not only grown","Emergency funds and liquidity: how much cash to keep, where to keep it, and why access matters","Family capital and wealth structures: how financially accomplished families think about trusts, estate planning, diversification, asset protection, and generational wealth","Common mistakes young earners make in their first years of income — and how to avoid them"] },
    { n:"10", title:"Public Relations & Crisis Communication", tagline:"Reputation is built quietly. It can be lost overnight.", sub:"Outside Specialist — PR Professional or Communications Executive",
      body:"A brand is not only what it sells. It is what people believe about it. In a world of screenshots, viral posts, public criticism, public criticism, failed responses, viral narratives, and reputational risk, reputation has become one of the most valuable assets a company or leader can have.\n\nThis module teaches students how public narrative is built, protected, and repaired. They learn the difference between earned, paid, and owned media; how journalists think; how a story becomes news; how social media can turn one mistake into a crisis; and why the first response often determines whether a situation is contained or made worse.\n\nStudents study famous corporate and founder reputation crises, then practice building statements, answering difficult questions, and communicating clearly when the room — or the public — is watching. The goal is not spin. The goal is judgment: knowing what to say, what not to say, when to speak, who should speak, and how to protect trust when it matters most.",
      learn:["Earned, paid, and owned media: how each serves a different purpose in building reputation","How journalists think: what makes a story, what gets ignored, and what turns into a headline","Founder and executive reputation: how personal conduct, interviews, social media, and public image affect trust","Crisis communication frameworks: what to say, when to say it, who speaks, and what must be avoided","The first 24 hours: why the initial response often determines whether a crisis is contained or amplified","Social media escalation: how screenshots, comments, bad apologies, and viral moments can reshape public perception","Statement writing: how to draft a clear, responsible, credible response without making the situation worse","Media interviews: how to answer difficult questions without losing composure or saying more than intended","Case studies: Tylenol 1982, Airbnb COVID-19, United Airlines 2017, WeWork, celebrity-founder crises, and modern social media backlash"] },
    { n:"11", title:"Industry Sectors Rotation", tagline:"Understand industries. Enter serious rooms prepared.", sub:"Monthly Rotating Guest Practitioners · 4 sectors in Foundation Semester",
      body:"Each month, students are introduced to a different industry through a working practitioner who knows it from the inside. The goal is not surface-level career exposure. It is to help students understand how industries actually operate: how money moves, where opportunity forms, what skills matter, what risks define the field, and what capabilities, habits, and judgment tend to matter in each field.\n\nDuring the Foundation Semester, students explore four major sectors — Technology & Startups, Finance & Investment, Real Estate, Sports & Auto Racing, and Media & Entertainment — while maintaining a running Sector Journal. In each entry, students document what they learned, how the industry works, what surprised them, what careers or ventures it may open, and what questions they would ask if they were sitting across from a founder, investor, executive, operator, athlete, creator, or industry leader in that field.",
      learn:[] },

  ];

  const warRoom = [
    { title:"Current Events & Business News Analysis", desc:"Students break down major business headlines, market shifts, leadership decisions, and global events, learning how to distinguish signal from noise." },
    { title:"Start-Up Simulations, Risk Management & Case Deconstruction", desc:"Students step into founder and executive roles, testing decisions around growth, competition, failure, crisis, and risk while analyzing 30–40 real companies by graduation." },
    { title:"Monthly Guest Industry Speaker", desc:"Once per month, students learn directly from an entrepreneur, executive, investor, operator, or specialist who brings applied insight from the field." },
    { title:"What Would You Have Done?", desc:"Students are placed at the exact pressure point of a real business story — before the outcome is known. They must make the call, argue their logic, and defend their judgment before discovering what actually happened." },
    { title:"Your Move", desc:"Students are placed inside a company in trouble. Revenue is falling, trust is breaking, competitors are closing in, or leadership has failed. Acting as the executive team, they must design a turnaround strategy and present it to faculty as if facing a skeptical board, investor, or founder." },
    { title:"Apply It Now", desc:"The lesson does not end with theory. Students immediately take the day's specialist insight and put it to work through live drills, strategic exercises, team challenges, and high-pressure simulations." },
    { title:"Command Decision", desc:"Students face the hardest kind of leadership decision: the one with no clean answer. Every option carries a cost. A team may have to choose between loyalty and truth, profit and responsibility, speed and safety, reputation and integrity, or protecting one priority while sacrificing another. There is no easy answer and no perfect script. Students must make the call, defend the tradeoff, explain who is affected, and prove they understand the consequences of the decision they are making." },
  ];

  const aoc = [
    { n:"01", title:"Presence & First Impressions", desc:"How you enter a room, introduce yourself, shake hands, make eye contact, and hold space. The difference between trying to impress and simply being present.", topics:["Posture and physical presence","Eye contact and confidence","Entering a room","Introductions","Handshakes","Voice and projection","Personal grooming and presentation","First-impression psychology"] },
    { n:"02", title:"The Art of Conversation", desc:"How to listen with genuine attention. How to ask questions that make people want to keep talking. How to hold a conversation with adults, professionals, and guests without defaulting to performance.", topics:["Conversation foundations","Asking intelligent questions","Active listening","Storytelling","Humor and wit","Reading social cues","Navigating difficult conversations","Carrying a dinner conversation"] },
    { n:"03", title:"Cultural Literacy", desc:"The shared references of serious cultural conversation — art, architecture, music, literature, history, philosophy. The ability to recognize and engage with ideas across disciplines.", topics:["History","Architecture","Fine art","Classical music","Literature","European cinema","Fashion and style history","Global cultures","Current affairs"] },
    { n:"04", title:"Philosophy & Decision-Making", desc:"Stoic philosophy as a practical framework — Marcus Aurelius, Seneca, Epictetus. Plato and Aristotle on virtue, reason, and leadership. Applied to modern business and life.", topics:["Stoicism","Aristotle","Virtue ethics","Duty and responsibility","Human nature","Critical thinking","Cognitive bias","Decision frameworks"] },
    { n:"05", title:"Executive Etiquette & Social Intelligence", desc:"Formal dining protocol. Professional correspondence. How to address people in different settings. How to enter and exit conversations gracefully.", topics:["Business dining","Event etiquette","Professional correspondence","Introductions and hosting","Networking etiquette","Meeting conduct","Professional dress","Travel etiquette"] },
    { n:"06", title:"Influence & Diplomacy", desc:"How influence works through trust, reputation, timing, discretion, and relationships rather than force or title. Historical case studies in diplomacy and statecraft.", topics:["Social intelligence","Persuasion","Negotiation psychology","Diplomacy","Reading the room","Building trust","Conflict resolution","Reputation"] },
    { n:"07", title:"Statesmanship & Leadership", desc:"Historical leadership case studies — Lincoln, Churchill, Mandela. What distinguishes statesmanship from performance, and leadership from management.", topics:["Historical leaders","Leadership under pressure","Responsibility","Stewardship","Public service","Long-term thinking","Legacy","Decision making during crisis"] },
    { n:"08", title:"Networking & Relationship Capital", desc:"How to build genuine professional relationships — rather than simply collecting contacts. What networking actually is: helping first, not asking first. How to maintain relationships over time.", topics:["Relationship building","Strategic networking","Introductions","Following up","Mentorship","Social capital","Hosting","Building trust over time"] },
    { n:"09", title:"Intellectual Depth", desc:"The habits of deep reading, sustained attention, and original thinking. How to form and defend an idea with clarity. Includes a recommended reading list and a one-page response exercise.", topics:["Literature","History's defining ideas","Economics","Technology","Society","Human behavior","Future trends"] },
    { n:"10", title:"Personal Development & Direction", desc:"Students reflect on who they are becoming: their values, ambitions, strengths, weaknesses, habits, standards, and personal definition of leadership. The module helps students articulate a leadership philosophy they can carry into interviews, essays, relationships, ventures, and future settings where character matters as much as performance.", topics:["Values","Reputation","Long-term goals","Leadership philosophy","Family and community","Personal development"] },
  ];

  const vMods = [
    { slug:null, n:"VM01", title:"Entrepreneurial Mindset & Business Fundamentals", tagline:"How businesses start. How founders think.", sub:"Deliverable: Problem statement + customer profile + initial value hypothesis",
      body:"Market sizing, idea validation, problem-solution fit, and different business models for specific markets. Students learn how to identify meaningful problems, evaluate opportunities, validate assumptions, and design business models capable of creating sustainable value. Through founder case studies and practical exercises, they develop the core venture thesis that will guide their work throughout the semester.",
      learn:["The entrepreneurial mindset — how founders identify problems, opportunities, and market gaps","Opportunity assessment — distinguishing between interesting ideas and scalable opportunities","Idea validation — testing whether an idea is worth pursuing before building","Market sizing — TAM, SAM, SOM, and what those numbers tell investors","Problem-solution fit — defining a problem precisely and matching it to a solution","Business model fundamentals — how ventures create, deliver, and capture value","Customer profiling — identifying users, buyers, and decision-makers","Value hypothesis development — articulating why customers would choose your solution"] },
    { slug:null, n:"VM02", title:"Competitive Analysis & Market Research", tagline:"Who else is doing this? Why would a customer choose you?", sub:"Deliverable: Competitive Map · Differentiation Statement · Customer Research Findings",
      body:"Students learn how to conduct customer interviews and what to listen for, how to evaluate competitors, understand market dynamics, and gather meaningful insights. The goal is to move beyond assumptions and build a venture based on evidence rather than opinion.",
      learn:["Competitive mapping — identifying direct, indirect, and substitute competitors","Porter’s Five Forces — analyzing industry attractiveness and competitive pressure","SWOT analysis — assessing strengths, weaknesses, opportunities, and threats","Value proposition design — why customers should choose you and creating meaningful differentiation","Primary market research — conducting customer interviews and surveys","Customer insight analysis — identifying patterns, pain points, and unmet needs","Market positioning — understanding where a venture fits within the competitive landscape","Differentiation strategy — building advantages competitors cannot easily replicate"] },
    { slug:null, n:"VM03", title:"Marketing, Branding & Customer Psychology", tagline:"Who is your customer. How do you reach them.", sub:"Deliverable: Brand Marketing Portfolio · Messaging Framework · Customer Acquisition Plan",
      body:"Students learn how successful ventures attract attention, build trust, and create demand in competitive markets. Through practical exercises, case studies, and applied examples, they learn how to build not just a company, but a brand that stands out. Students explore brand strategy, storytelling, customer psychology, and competitive positioning to understand why some ventures break through the noise while others are ignored.\n\nThe module guides students through the creation of a complete Venture Launch Portfolio, including brand positioning, logo concepts, visual identity systems, brand guidelines, mission and vision statements, taglines and mottos, tone of voice frameworks, storytelling narratives, and customer-facing messaging. Students learn how to establish and manage professional social media profiles, create advertising accounts, develop content strategies, and build the foundational marketing infrastructure required for launch.\n\nBy the end of the module, students will have developed the positioning, messaging, branding assets, and customer acquisition foundations needed to reach the right audience, communicate value clearly, build credibility, and create a brand that customers recognize, remember, trust, and advocate for.",
      learn:["Customer segmentation — defining your ideal customer with precision, not generality","Brand identity portfolio — name, positioning, voice, visual presence, and what your brand actually stands for","Customer acquisition fundamentals — how businesses attract their first customers","The marketing funnel — awareness, consideration, conversion, and retention","Consumer psychology — why people buy, hesitate, trust, compare, and decide","Persuasion principles — Cialdini’s six drivers: reciprocity, commitment, social proof, authority, liking, scarcity","Digital marketing channels — social media, content marketing, email, SEO, paid acquisition","Messaging and copywriting — writing clear headlines, offers, and calls to action","Positioning strategy — occupying a distinct, defensible place in the customer’s mind","Storytelling in business — using narrative to create engagement","Growth experiments — testing marketing ideas with limited resources","Brand consistency — creating a coherent customer experience across touchpoints"] },
    { slug:null, n:"VM04", title:"AI as a Business Tool", tagline:"A tool for research, analysis, and execution — used with judgment.", sub:"Deliverable: AI-Built Market Research Report · AI Competitive Intelligence Brief · Venture AI Workflow Stack",
      body:"Artificial intelligence is rapidly becoming one of the most powerful leverage tools available to founders, executives, and professionals. The advantage increasingly belongs to those who can combine judgment, strategy, and intelligent systems.\n\nStudents learn how entrepreneurs and business leaders use AI to accelerate research, analyze markets, understand competitors, generate content, improve decision-making, streamline operations, and increase productivity. Rather than treating AI as a novelty, students learn how to integrate it into real business workflows and apply it directly to their own venture.\n\nThe module focuses on practical execution. Students use AI to conduct market research, generate customer insights, build competitive intelligence reports, develop marketing assets, create investor presentation materials, and automate repetitive tasks. Equally important, they learn where AI breaks down, where hallucinations occur, and why human judgment remains the ultimate competitive advantage.",
      learn:["AI-powered market research — analyzing industries, trends, customers, and competitors at scale","AI instruction for business — designing prompts and workflows that produce useful, reliable, and actionable outputs","Competitive intelligence workflows — gathering, organizing, and synthesizing information faster than traditional methods","AI for marketing and content creation — generating messaging, copy, campaigns, and creative assets","AI-assisted presentation and pitch development — building investor decks, reports, and business documents","Workflow automation — identifying repetitive tasks and designing systems and workflows that save time","AI for customer analysis — uncovering patterns, feedback themes, and customer insights","Evaluating AI tools and platforms — understanding strengths, limitations, costs, and use cases","AI ethics and responsible use — privacy, bias, intellectual property, and transparency","Human judgment as a competitive advantage — knowing when to trust AI, when to challenge it, and when to ignore it entirely"] },
    { slug:null, n:"VM05", title:"Sales, Persuasion & The Art of Influence", tagline:"Founders must learn to communicate value, earn trust, and move ideas forward.", sub:"Deliverable: Sales Strategy · Partnership Outreach Plan · Complete Investor Pitch Deck · Rehearsed 8-Minute Presentation",
      body:"Founders do not simply build products. They convince customers to buy, partners to collaborate, funders or advisors to take the idea seriously, employees to join, and communities to believe in a vision that does not yet exist.\n\nThis module explores the psychology and mechanics of influence, persuasion, negotiation, and sales. Students learn how trust is built, how buying decisions are made, why people say yes, and how successful entrepreneurs move people from interest to action.\n\nThe module combines practical sales training, customer conversations, negotiation strategy, partnership development, and panel communication. Students learn how to conduct discovery conversations, qualify opportunities, handle objections, negotiate confidently, build strategic relationships, and communicate value persuasively across a wide range of business situations.\n\nBy the end of the module, every student will have developed a complete venture presentation deck, delivered multiple rehearsals, refined their presentation style, and prepared to defend their venture under live questioning.",
      learn:["Sales psychology — understanding how customers evaluate and make decisions","Discovery conversations — asking questions that uncover needs, motivations, and objections","Persuasion psychology — trust, credibility, influence, and behavioral decision-making","Negotiation fundamentals — creating value while protecting interests","Objection handling — responding confidently to skepticism and concerns","Partnership development — approaching potential collaborators, advisors, sponsors, and stakeholders","Relationship capital — building long-term professional networks and opportunities","Venture presentation architecture — problem, solution, market, model, validation, team, and next step","Storytelling for founders — turning a venture into a compelling narrative rather than a collection of facts","Slide design and presentation structure — building professional venture presentation decks","Executive presence — confidence, composure, body language, and delivery under pressure","High-pressure Q&A practice — handling investor, customer, and stakeholder questions with clarity and precision","Closing and commitment — moving conversations from interest to action, support, investment, or partnership"] },
    { slug:null, n:"VM06", title:"Financial Modeling for Founders", tagline:"Strong ventures are built on sound financial assumptions, not guesswork.", sub:"Deliverable: Complete Financial Model · Revenue Projections · Cost Structure · 18-Month P&L",
      body:"Great founders do not need to be accountants, but they must understand the numbers that drive their business. This module teaches students how to translate a venture idea into a financial model faculty, advisors, and experienced practitioners can evaluate.\n\nStudents learn how revenue is generated, what it costs to operate, how margins are calculated, how much capital is needed, and how long a venture can operate before additional capital is required. They build realistic assumptions instead of fantasy projections and learn how small changes in pricing, costs, conversion rates, or customer acquisition can dramatically affect the business.\n\nThe module also introduces students to the financial questions investors care about most: Can this business make money? Can it scale? How much does it cost to acquire a customer? How long is the runway? What must be true for this venture to work?\n\nBy the end of the module, students will have built a founder-level financial model with revenue projections, cost structure, unit economics, scenario assumptions, and an 18-month profit-and-loss forecast.",
      learn:["Revenue modeling — building bottom-up projections from real assumptions","Pricing strategy — understanding how price affects demand, margin, and positioning","Unit economics — CAC, LTV, contribution margin, and payback period","Cost structure — fixed costs, variable costs, operating expenses, and burn rate","Runway and cash planning — understanding how long a venture can operate before needing more capital","Break-even analysis — identifying when revenue can cover expenses","Scenario planning — modeling base case, upside case, and downside case outcomes","Profit-and-loss fundamentals — revenue, expenses, gross margin, operating income, and net profit","Investor assumptions — understanding which financial claims investors challenge first","Cap table basics — how equity is structured, diluted, and valued"] },
    { slug:null, n:"VM07", title:"Capital Strategy & Funding Fundamentals", tagline:"From bootstrapping, crowdfunding and customer-funded growth to angel investors and institutional capital.", sub:"Deliverable: Full Funding Strategy · One-Page Fundraising Brief",
      body:"Founders can access funding from many sources throughout a company’s growth journey, including friends and family financing, angel investors, startup accelerators, crowdfunding customer-funded growth to angels, grants, crowdfunding, and venture capital. Where that capital comes from, what it costs, and whether it is worth taking are critical strategic decisions.\n\nMany founders assume venture capital is the goal. In reality, successful businesses are funded in many different ways, and the smartest financing strategy depends on the venture itself. This module teaches students how capital flows through the entrepreneurial ecosystem, how investors evaluate opportunities, and how founders make financing decisions that support long-term growth.\n\nStudents explore the full funding landscape, from bootstrapping and customer-funded growth to angel investors, venture capital, grants, accelerators, strategic partnerships, and crowdfunding. They learn how ownership changes over time, what dilution actually means, how fundraising impacts control, and why not every form of capital serves the same kind of company.\n\nThe module also introduces students to the legal and economic mechanics of fundraising, including SAFE notes, convertible notes, equity financing, valuations, term sheets, and investor expectations. Through case studies, venture analyzes, and a faculty-guided mock term sheet negotiation, students gain a practical understanding of how founders raise capital and negotiate from a position of knowledge.\n\nBy the end of the module, students will have developed a funding strategy tailored to their venture, understand the implications of different financing paths, and be able to discuss fundraising with the confidence and vocabulary of an early-stage founder.",
      learn:["The funding landscape — bootstrapping, customer-funded growth, angels, venture capital, crowdfunding, grants, accelerators, and strategic partnerships","Founder-investor fit — understanding which funding sources are appropriate for different types of ventures","Venture capital fundamentals — how venture firms operate, invest, and generate returns","SAFE notes, convertible notes, and equity financing — how each structure works and when founders use them","Valuation fundamentals — what determines a company’s value and why valuations matter","Dilution and ownership — how investment affects founder equity and long-term control","Cap table mechanics — understanding ownership structure across multiple financing rounds","Investor psychology — what investors look for and what causes them to pass","Term sheets — the key clauses every founder should understand before accepting capital","Fundraising strategy — determining when to raise, how much to raise, and what capital is actually needed"] },
    { slug:null, n:"VM08", title:"Legal Foundations for Founders", tagline:"Understand what you are signing before you sign it.", sub:"Outside Specialist — Practicing Attorney with Startup Experience",
      body:"Most founders do not make legal mistakes because they are careless. They make them because they do not yet know what can go wrong: the wrong entity, unclear ownership, missing IP protection, weak founder agreements, careless contracts, or terms they did not fully understand until it was too late.\n\nThis module gives students the legal literacy every young founder needs before building, partnering, raising money, or signing anything consequential. It is a practical introduction to the structures, documents, and decisions that shape the first years of a company.\n\nStudents learn how companies are formed, how ownership is divided, how intellectual property is protected, how contracts create obligations, and why the details of founder agreements, NDAs, equity terms, and term sheets matter before a serious business relationship begins.",
      learn:["Business entity types: LLC, C-corp, S-corp, sole proprietorship, and when each structure makes sense","Equity structure: ownership splits, dilution, vesting schedules, cliff periods, and what happens when a co-founder leaves","Founder agreements: roles, responsibilities, equity, decision rights, vesting, IP assignment, and dispute prevention","Intellectual property: trademarks, copyrights, patents, trade secrets, ownership, and protection of what students build","Contracts and NDAs: what makes an agreement binding, what clauses create risk, and what should never be signed casually","Employment and contractor basics: IP assignment, confidentiality, compensation, and early-team agreements","Term sheet basics: valuation, equity, liquidation preference, control rights, investor protections, and the clauses founders must understand","Cap tables: how ownership changes over time and why early mistakes become expensive later","How to work with a lawyer: what to ask, what to understand yourself, and when professional legal guidance is necessary"] },
  ];

