            <button onClick={()=>setPage&&setPage("faculty")} style={{ fontFamily:sans, fontSize:9, letterSpacing:"0.25em", padding:"14px 32px", background:"transparent", border:"1px solid rgba(164,141,110,.45)", color:"#E4D5C1", textTransform:"uppercase", cursor:"pointer", fontWeight:600 }}>Meet the Faculty →</button>
